/**
 * Webhook notification adapter.
 *
 * Implements NotificationAdapter for the 'webhook' channel.
 * Features:
 * - JSON payload formatting from NotificationPayload
 * - URL validation
 * - Pluggable transport (swap WebhookTransport for real HTTP client)
 * - Retry support with configurable attempts
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the webhook adapter.
 */
export interface WebhookConfig {
  url: string;
  secret?: string;
  maxRetries?: number;
  headers?: Record<string, string>;
}

/**
 * The JSON body POSTed to the webhook endpoint.
 */
export interface WebhookRequestBody {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  channel: string;
  priority: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/**
 * Transport interface — swap this implementation for a real
 * HTTP client (fetch, axios, etc.).
 */
export interface WebhookTransport {
  post(
    url: string,
    body: WebhookRequestBody,
    headers: Record<string, string>,
  ): Promise<{ requestId: string; statusCode: number }>;
}

/**
 * Default in-memory transport for development and testing.
 * Stores all posted payloads for later inspection.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private requests: Array<{
    url: string;
    body: WebhookRequestBody;
    headers: Record<string, string>;
    requestId: string;
    postedAt: Date;
  }> = [];

  async post(
    url: string,
    body: WebhookRequestBody,
    headers: Record<string, string>,
  ): Promise<{ requestId: string; statusCode: number }> {
    const requestId = `whk-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    this.requests.push({ url, body, headers, requestId, postedAt: new Date() });
    return { requestId, statusCode: 200 };
  }

  getRequests(): Array<{
    url: string;
    body: WebhookRequestBody;
    headers: Record<string, string>;
    requestId: string;
    postedAt: Date;
  }> {
    return [...this.requests];
  }

  clear(): void {
    this.requests = [];
  }
}

const URL_REGEX = /^https?:\/\/[^\s/$.?#].[^\s]*$/;

/**
 * Validate that a string looks like an HTTP(S) URL.
 */
export function isValidWebhookUrl(url: string): boolean {
  return URL_REGEX.test(url);
}

/**
 * Format a NotificationPayload into a WebhookRequestBody.
 */
export function formatWebhookPayload(payload: NotificationPayload): WebhookRequestBody {
  const notificationType = (payload.metadata?.notificationType as string) ?? 'notification';

  return {
    event: notificationType,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel: payload.channel,
    priority: payload.priority,
    metadata: payload.metadata,
    timestamp: new Date().toISOString(),
  };
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;
  private config: Required<Pick<WebhookConfig, 'url' | 'maxRetries'>> &
    Pick<WebhookConfig, 'secret' | 'headers'>;

  constructor(config: WebhookConfig, transport?: WebhookTransport) {
    this.config = {
      url: config.url,
      secret: config.secret,
      maxRetries: config.maxRetries ?? 2,
      headers: config.headers,
    };
    this.transport = transport ?? new InMemoryWebhookTransport();
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!isValidWebhookUrl(this.config.url)) {
      this.logger.warn(`Invalid webhook URL: ${this.config.url}`);
      return {
        success: false,
        notificationId: `webhook-${Date.now()}`,
        channel: 'webhook',
        error: `Invalid webhook URL: ${this.config.url}`,
      };
    }

    const body = formatWebhookPayload(payload);

    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      ...this.config.headers,
    };

    if (this.config.secret) {
      headers['X-Webhook-Secret'] = this.config.secret;
    }

    let lastError: unknown;
    const maxAttempts = this.config.maxRetries + 1;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        const result = await this.transport.post(this.config.url, body, headers);
        this.logger.info(
          `Webhook delivered to ${this.config.url}: "${payload.subject}" (requestId: ${result.requestId})`,
        );
        return {
          success: true,
          notificationId: result.requestId,
          channel: 'webhook',
        };
      } catch (error) {
        lastError = error;
        this.logger.warn(
          `Webhook attempt ${attempt}/${maxAttempts} failed for ${this.config.url}: ${error}`,
        );
      }
    }

    const errorMsg = lastError instanceof Error ? lastError.message : String(lastError);
    this.logger.error(
      `Webhook delivery failed after ${maxAttempts} attempts to ${this.config.url}: ${errorMsg}`,
    );
    return {
      success: false,
      notificationId: `webhook-failed-${Date.now()}`,
      channel: 'webhook',
      error: `Delivery failed after ${maxAttempts} attempts: ${errorMsg}`,
    };
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryWebhookTransport).
   */
  getTransport(): WebhookTransport {
    return this.transport;
  }
}

